public class Adapter {
    interface Fahrenheit { double getF(); }
    static class CelsiusSensor { double getC() { return 100.0; } }
    static class TempAdapter implements Fahrenheit {
        private final CelsiusSensor s;
        TempAdapter(CelsiusSensor s) { this.s = s; }
        public double getF() { return s.getC() * 9.0 / 5.0 + 32; }
    }
    public static void main(String[] args) {
        Fahrenheit f = new TempAdapter(new CelsiusSensor());
        System.out.println(f.getF());
    }
}
